// src/pages/Leave/LeavePage.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Clock, AlertCircle,
  Send, BarChart2, Calendar, Edit3, Bell, RefreshCw, Users,
  TrendingUp, AlertTriangle, Settings, FileText, Upload,
  ChevronDown, ChevronUp, Filter, Download, Search,
  ArrowRightLeft, Layers, Shield, RotateCcw, Trash2
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI, notificationAPI } from '../../api/services';
import { Modal, Badge, SkeletonCard, EmptyState, InlineSpinner, StatCard } from '../../components/common';
import { useAuth } from '../../context/AuthContext';

const STATUS_LABEL = {
  SUBMITTED: 'Submitted', PENDING_MANAGER: 'Pending Approval',
  PendingManager: 'Pending Approval', PendingHR: 'Pending HR',
  PENDING_HR: 'Pending HR', APPROVED: 'Approved', REJECTED: 'Rejected',
  CANCELLED: 'Cancelled', CANCELED: 'Cancelled', DRAFT: 'Draft',
  Submitted: 'Submitted', Pending: 'Pending Approval',
  Approved: 'Approved', Rejected: 'Rejected', Cancelled: 'Cancelled',
  submitted: 'Submitted', pending: 'Pending Approval',
  approved: 'Approved', rejected: 'Rejected', cancelled: 'Cancelled',
};

const STATUS_OPTIONS = [
  { value: '', label: 'All' },
  { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending Approval' },
  { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' },
  { value: 'CANCELLED', label: 'Cancelled' },
];

const STATUS_HISTORY = [
  { value: '', label: 'All' },
  { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending' },
  { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' },
  { value: 'CANCELLED', label: 'Cancelled' },
];

// ─── HELPERS ──────────────────────────────────────────────────────────
const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');
const statusMatches = (reqStatus, filterValue) => {
  if (!filterValue) return true;
  const rs = normStatus(reqStatus);
  const fv = normStatus(filterValue);
  if (rs === fv) return true;
  const allPending = new Set(['PENDINGMANAGER','PENDINGHR','SUBMITTED','PENDING','DRAFT','PENDINGDOCTOR']);
  if (fv === 'PENDINGMANAGER' && allPending.has(rs)) return true;
  return false;
};
const isFinalStatus = s => ['APPROVED','REJECTED','CANCELLED','CANCELED','Approved','Rejected','Cancelled','approved','rejected','cancelled'].includes(normStatus(s));

const toArr = (r) => {
  if (!r) return [];
  const d = r.data || r;
  if (Array.isArray(d)) return d;
  if (Array.isArray(d?.requests)) return d.requests;
  if (d?.data && Array.isArray(d.data)) return d.data;
  if (d?.data?.requests && Array.isArray(d.data.requests)) return d.data.requests;
  return [];
};

// ─── BALANCE CARD ─────────────────────────────────────────────────────
function BalanceCard({ balance, loading }) {
  if (loading) return <SkeletonCard />;
  const name      = balance.leaveTypeName  || balance.LeaveTypeName  || balance.name || balance.type || 'Leave';
  const used      = Number(balance.usedDays      ?? balance.UsedDays      ?? 0);
  const pending   = Number(balance.pendingDays   ?? balance.PendingDays   ?? 0);
  const entitled  = Number(balance.entitledDays  ?? balance.EntitledDays  ?? 0);
  const carryOver = Number(balance.carryOverDays ?? balance.CarryOverDays ?? 0);
  const adjusted  = Number(balance.adjustedDays  ?? balance.AdjustedDays  ?? 0);
  const remaining = Number(
    balance.remainingDays ?? balance.RemainingDays ??
    Math.max(0, entitled + carryOver + adjusted - used - pending)
  );
  const maxDays = Number(balance.maxDaysPerYear ?? (entitled + carryOver + adjusted));
  const total   = maxDays || (used + remaining) || 1;
  const pct     = total > 0 ? Math.round((remaining / total) * 100) : 0;

  const COLOR_MAP = {
    Annual: 'var(--blue)', Sick: 'var(--green)', Medical: 'var(--green)',
    Emergency: 'var(--red)', Accidental: 'var(--red)', Sabbatical: 'var(--purple)',
    Maternity: 'var(--purple)', Paternity: 'var(--purple)',
  };
  const color = Object.entries(COLOR_MAP).find(([k]) => name.includes(k))?.[1] || 'var(--gold)';

  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
        <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', fontWeight: 500, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
          {name}
        </div>
        <CalendarDays size={18} style={{ color }} />
      </div>
      <div className="stat-card-value" style={{ color }}>{remaining}</div>
      <div className="stat-card-label">days remaining of {maxDays}</div>
      <div className="stat-card-progress" style={{ marginTop: 12 }}>
        <div className="stat-card-progress-bar" style={{ width: `${pct}%`, background: color }} />
      </div>
      <div className="stat-card-meta">
        <span>{used} used{pending > 0 ? ` · ${pending} pending` : ''}{carryOver > 0 ? ` · ${carryOver} carried` : ''}</span>
        <span>{pct}%</span>
      </div>
    </div>
  );
}

// ─── REQUEST ROW ──────────────────────────────────────────────────────
function RequestRow({ req, onAction, onEdit, isManager, userRole }) {
  const [acting, setActing] = useState('');
  const name    = req.LeaveType?.LeaveTypeName || req.leaveType?.LeaveTypeName || req.leaveTypeName || req.LeaveTypeName || req.type || '—';
  const from    = (req.StartDate || req.startDate) ? new Date(req.StartDate || req.startDate).toLocaleDateString() : '—';
  const to      = (req.EndDate   || req.endDate)   ? new Date(req.EndDate   || req.endDate).toLocaleDateString()   : '—';
  const days    = req.TotalDays ?? req.totalDays ?? req.numberOfDays ?? req.days ?? '—';
  const status  = req.Status || req.status || 'SUBMITTED';
  const id      = req.LeaveRequestID || req.leaveRequestId || req.id;
  const empName = req.Employee?.FullName || req.employee?.FullName || req.employeeName
                || [req.employee?.firstName, req.employee?.lastName].filter(Boolean).join(' ') || '—';

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  const isFinal      = isFinalStatus(status);
  const isActionable = !isFinal;
  const isCancellable = !isFinal;
  const displayLabel = STATUS_LABEL[status] || status;

  return (
    <tr>
      <td>
        <div style={{ fontWeight: 500 }}>{name}</div>
        {(req.Reason || req.reason) && (
          <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: 2 }}>
            {(req.Reason || req.reason).slice(0, 50)}…
          </div>
        )}
      </td>
      {isManager && <td><div style={{ fontWeight: 500 }}>{empName}</div></td>}
      <td style={{ fontSize: '0.82rem' }}>{from} → {to}</td>
      <td>{days !== '—' ? `${days} day${days !== 1 ? 's' : ''}` : '—'}</td>
      <td>
        <span style={{
          display: 'inline-block', padding: '3px 10px', borderRadius: 20, fontSize: '0.75rem', fontWeight: 600,
          background: normStatus(status) === 'APPROVED' ? 'rgba(34,197,94,0.15)' :
                      normStatus(status) === 'REJECTED' ? 'rgba(239,68,68,0.15)' :
                      normStatus(status) === 'CANCELLED' ? 'rgba(156,163,175,0.15)' : 'rgba(251,191,36,0.15)',
          color:      normStatus(status) === 'APPROVED' ? '#16a34a' :
                      normStatus(status) === 'REJECTED' ? '#dc2626' :
                      normStatus(status) === 'CANCELLED' ? '#6b7280' : '#b45309',
        }}>
          {displayLabel}
        </span>
      </td>
      {isManager && (
        <td style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', maxWidth: 160 }}>
          {(req.Reason || req.reason || '—').slice(0, 60)}{(req.Reason || req.reason || '').length > 60 ? '…' : ''}
        </td>
      )}
      <td>
        <div style={{ display: 'flex', gap: 6 }}>
          {isManager && isActionable && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>
                {acting === 'approve' ? <InlineSpinner /> : <><Check size={13} /> Approve</>}
              </button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>
                {acting === 'reject' ? <InlineSpinner /> : <><X size={13} /> Reject</>}
              </button>
            </>
          )}
          {!isManager && isCancellable && (
            <>
              {onEdit && <button className="btn btn-ghost btn-sm" onClick={() => onEdit(req)}><Edit3 size={14} /> Edit</button>}
              <button className="btn btn-ghost btn-sm" onClick={() => act('cancel')} disabled={!!acting}>
                {acting === 'cancel' ? <InlineSpinner /> : 'Cancel'}
              </button>
            </>
          )}
        </div>
      </td>
    </tr>
  );
}

// ─── RESTORED ORIGINAL SUBMIT FORM ────────────────────────────────────
function SubmitLeaveForm({ leaveTypes, onSubmit, loading }) {
  const [form, setForm] = useState({ LeaveTypeID: '', startDate: '', endDate: '', reason: '', isHalfDay: false, documentReference: '' });
  const [errors, setErrors] = useState({});
  const set = (k, v) => { setForm(f => ({ ...f, [k]: v })); setErrors(e => ({ ...e, [k]: '' })); };

  const validate = () => {
    const e = {};
    if (!form.LeaveTypeID) e.LeaveTypeID = 'Select a leave type';
    if (!form.startDate)   e.startDate   = 'Required';
    if (!form.endDate)     e.endDate     = 'Required';
    if (form.startDate && form.endDate && form.endDate < form.startDate)
      e.endDate = 'End date must be after start date';
    return e;
  };

  const handle = () => {
    const e = validate();
    if (Object.keys(e).length) { setErrors(e); return; }

    // Strict Payload
    onSubmit({
      LeaveTypeID:       parseInt(form.LeaveTypeID, 10),
      StartDate:         new Date(form.startDate).toISOString(),
      EndDate:           new Date(form.endDate).toISOString(),
      IsHalfDay:         form.isHalfDay,
      Reason:            form.reason || null,
      DocumentReference: form.documentReference || null,
    });
  };

  const days = form.startDate && form.endDate
    ? Math.max(0, Math.round((new Date(form.endDate) - new Date(form.startDate)) / 86400000) + 1)
    : 0;

  return (
    <>
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 20 }}>
        {[{l:'Leave Type',done:!!form.LeaveTypeID},{l:'Dates',done:!!(form.startDate&&form.endDate)},{l:'Details',done:false}].map((s,i,arr) => (
          <React.Fragment key={i}>
            <div style={{ display:'flex', alignItems:'center', gap:5, fontSize:'0.75rem',
              color: s.done ? '#16a34a' : 'var(--text-secondary)', fontWeight: s.done ? 600 : 400 }}>
              <span style={{ width:18, height:18, borderRadius:'50%', display:'inline-flex', alignItems:'center',
                justifyContent:'center', fontSize:'0.6rem', fontWeight:700,
                background: s.done ? 'rgba(34,197,94,0.15)' : 'var(--surface-alt,#2a2a3a)',
                color: s.done ? '#16a34a' : 'var(--text-muted)', border:'1px solid', borderColor: s.done ? 'rgba(34,197,94,0.4)':'var(--border)' }}>
                {s.done ? '✓' : i+1}
              </span>
              {s.l}
            </div>
            {i < arr.length-1 && <span style={{flex:1, height:1, background:'var(--border)', margin:'0 4px'}} />}
          </React.Fragment>
        ))}
      </div>

      <div className="form-group">
        <label className="form-label required">Leave Type</label>
        <select className="form-select" value={form.LeaveTypeID} onChange={e => set('LeaveTypeID', e.target.value)}>
          <option value="">— Select a leave type —</option>
          {leaveTypes.map(t => {
            const id   = t.leaveTypeId  || t.LeaveTypeID  || t.id;
            const name = t.leaveTypeName || t.LeaveTypeName || t.name;
            return <option key={id} value={id}>{name}</option>;
          })}
        </select>
        {errors.LeaveTypeID && <div className="form-error">{errors.LeaveTypeID}</div>}
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label required">Start Date</label>
          <input className="form-input" type="date" value={form.startDate} min={new Date().toISOString().split('T')[0]} onChange={e => set('startDate', e.target.value)} />
          {errors.startDate && <div className="form-error">{errors.startDate}</div>}
        </div>
        <div className="form-group">
          <label className="form-label required">End Date</label>
          <input className="form-input" type="date" value={form.endDate} min={form.startDate || new Date().toISOString().split('T')[0]} onChange={e => set('endDate', e.target.value)} />
          {errors.endDate && <div className="form-error">{errors.endDate}</div>}
        </div>
      </div>

      {days > 0 && (
        <div style={{ padding:'10px 14px', background:'rgba(34,197,94,0.07)', border:'1px solid rgba(34,197,94,0.2)', borderRadius:'var(--radius-md)', marginBottom:14, fontSize:'0.85rem', color:'#16a34a', fontWeight:500 }}>
          📅 <strong>{days} calendar day{days!==1?'s':''}</strong>
          <span style={{opacity:0.7,marginLeft:6,fontWeight:400}}>(net working days confirmed on submit)</span>
        </div>
      )}

      <div className="form-group">
        <label style={{display:'flex',alignItems:'center',gap:8,cursor:'pointer',fontSize:'0.875rem',userSelect:'none'}}>
          <input type="checkbox" checked={form.isHalfDay} onChange={e => set('isHalfDay', e.target.checked)} />
          <span>Half-day <span style={{color:'var(--text-secondary)',fontSize:'0.78rem'}}>(0.5 days deducted)</span></span>
        </label>
      </div>

      <div className="form-group">
        <label className="form-label">Reason <span style={{color:'var(--text-secondary)',fontSize:'0.76rem',fontWeight:400,marginLeft:6}}>optional</span></label>
        <textarea className="form-textarea" rows={2} value={form.reason} onChange={e => set('reason', e.target.value)} placeholder="Briefly describe the reason for this leave request..." />
      </div>

      <div className="form-group">
        <label className="form-label">Document Reference <span style={{color:'var(--text-secondary)',fontSize:'0.76rem',fontWeight:400,marginLeft:6}}>required for sick &gt;1 day · maternity</span></label>
        <input className="form-input" type="text" value={form.documentReference} onChange={e => set('documentReference', e.target.value)} placeholder="Medical cert no. …" />
      </div>

      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center', marginTop:16, paddingTop:14, borderTop:'1px solid var(--border-light)'}}>
        <button className="btn btn-ghost" type="button" onClick={() => { setForm({LeaveTypeID:'',startDate:'',endDate:'',reason:'',isHalfDay:false,documentReference:''}); setErrors({}); }} disabled={loading}>
          Clear form
        </button>
        <button className="btn btn-primary" onClick={handle} disabled={loading||!form.LeaveTypeID||!form.startDate||!form.endDate}>
          {loading ? <InlineSpinner /> : <><Send size={15} style={{marginRight:6}}/>Submit Request</>}
        </button>
      </div>
    </>
  );
}

// ─── RESTORED OVERRIDE PANEL (LV-026) ─────────────────────────────────
function OverridePanel({ requests, onOverride }) {
  const [selected, setSelected] = useState('');
  const [newStatus, setNewStatus] = useState('APPROVED'); // Ensure default is APPROVED
  const [reason, setReason] = useState('');

  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card-header">
        <div className="card-title"><Shield size={15} style={{ marginRight: 6 }} />Override Manager Decision</div>
      </div>
      <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: 12 }}>
        HR Manager can override any approved or rejected decision. This action is logged.
      </p>
      <div className="form-group">
        <label className="form-label">Select Request</label>
        <select className="form-select" value={selected} onChange={e => setSelected(e.target.value)}>
          <option value="">— Select a finalized request —</option>
          {requests.filter(r => isFinalStatus(r.Status || r.status)).map(r => {
            const id = r.LeaveRequestID || r.leaveRequestId || r.id;
            const emp = r.employeeName || r.Employee?.FullName || id;
            const type = r.leaveTypeName || r.LeaveType?.LeaveTypeName || '';
            return <option key={id} value={id}>{emp} — {type} ({r.Status || r.status})</option>;
          })}
        </select>
      </div>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label">Override To</label>
          <select className="form-select" value={newStatus} onChange={e => setNewStatus(e.target.value)}>
            <option value="APPROVED">Approved</option>
            <option value="REJECTED">Rejected</option>
          </select>
        </div>
      </div>
      <div className="form-group">
        <label className="form-label required">Override Reason</label>
        <textarea className="form-textarea" rows={2} value={reason} onChange={e => setReason(e.target.value)} placeholder="Provide justification for override…" />
      </div>
      <button className="btn btn-primary btn-sm" disabled={!selected || !reason.trim()}
        onClick={() => { onOverride(selected, newStatus, reason); setSelected(''); setReason(''); }}>
        Apply Override
      </button>
    </div>
  );
}

// ─── RESTORED DELEGATION PANEL (LV-023) ───────────────────────────────
function DelegationPanel({ onDelegate }) {
  const [delegateTo, setDelegateTo] = useState('');
  const [until, setUntil] = useState('');
  const [active, setActive] = useState(false);

  const handleActivate = () => {
    // Calling backend with 0 as a dummy ID since it's a general delegation
    onDelegate(0, { delegateId: parseInt(delegateTo, 10), startDate: new Date().toISOString(), endDate: new Date(until).toISOString() });
    setActive(true);
  };

  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card-header">
        <div className="card-title"><Users size={15} style={{ marginRight: 6 }} />Approval Delegation</div>
        {active && <span className="badge" style={{ background: 'rgba(34,197,94,0.15)', color: '#16a34a', fontSize: '0.72rem' }}>Active</span>}
      </div>
      <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: 12 }}>
        Delegate your approval authority to another manager while you're away.
      </p>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label">Delegate To (Employee ID)</label>
          <input className="form-input" type="text" value={delegateTo} onChange={e => setDelegateTo(e.target.value)} placeholder="e.g. 1042" />
        </div>
        <div className="form-group">
          <label className="form-label">Delegate Until</label>
          <input className="form-input" type="date" value={until} onChange={e => setUntil(e.target.value)} />
        </div>
      </div>
      <div style={{ display: 'flex', gap: 8 }}>
        <button className="btn btn-primary btn-sm" disabled={!delegateTo || !until} onClick={handleActivate}>
          Activate Delegation
        </button>
        {active && (
          <button className="btn btn-ghost btn-sm" onClick={() => { setActive(false); toast.success('Delegation revoked'); }}>
            Revoke
          </button>
        )}
      </div>
    </div>
  );
}

// ─── RESTORED PAYROLL SYNC PANEL (LV-044) ──────────────────────────────
function PayrollSyncPanel({ onSync }) {
  const [syncing, setSyncing] = useState(false);
  const [lastSync, setLastSync] = useState(null);

  const handlePayrollSync = async () => {
    setSyncing(true);
    try {
      await onSync();
      setLastSync(new Date().toLocaleString());
    } finally { setSyncing(false); }
  };

  return (
    <div style={{ padding: '12px 16px', background: 'var(--surface-alt,#1e1e2e)', borderRadius: 'var(--radius-md)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
      <div>
        <div style={{ fontWeight: 600, fontSize: '0.875rem', display: 'flex', alignItems: 'center', gap: 6 }}>
          <ArrowRightLeft size={14} />Payroll Sync
        </div>
        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: 2 }}>
          {lastSync ? `Last synced: ${lastSync}` : 'Not yet synced this session'}
        </div>
      </div>
      <button className="btn btn-primary btn-sm" onClick={handlePayrollSync} disabled={syncing}>
        {syncing ? <InlineSpinner /> : <><RefreshCw size={13} style={{ marginRight: 4 }} />Sync Now</>}
      </button>
    </div>
  );
}

// ─── RESTORED MODALS ──────────────────────────────────────────────────
function EditRequestModal({ req, onSave, onClose, loading }) {
  const [form, setForm] = useState({
    startDate: (req.StartDate || req.startDate || '').split('T')[0],
    endDate:   (req.EndDate   || req.endDate   || '').split('T')[0],
    reason:    req.Reason     || req.reason    || '',
  });

  return (
    <Modal title="Edit Leave Request" onClose={onClose}>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label required">Start Date</label>
          <input className="form-input" type="date" value={form.startDate} onChange={e => setForm({...form, startDate: e.target.value})} />
        </div>
        <div className="form-group">
          <label className="form-label required">End Date</label>
          <input className="form-input" type="date" value={form.endDate} min={form.startDate} onChange={e => setForm({...form, endDate: e.target.value})} />
        </div>
      </div>
      <div className="form-group">
        <label className="form-label">Reason</label>
        <textarea className="form-textarea" rows={2} value={form.reason} onChange={e => setForm({...form, reason: e.target.value})} />
      </div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
        <button className="btn btn-ghost" onClick={onClose} disabled={loading}>Cancel</button>
        <button className="btn btn-primary" onClick={() => onSave({ StartDate: form.startDate, EndDate: form.endDate, Reason: form.reason })} disabled={loading || !form.startDate || !form.endDate}>
          {loading ? <InlineSpinner /> : 'Save Changes'}
        </button>
      </div>
    </Modal>
  );
}

function ReasonModal({ title, placeholder, onConfirm, onClose, loading }) {
  const [reason, setReason] = useState('');
  return (
    <Modal title={title} onClose={onClose}>
      <div className="form-group">
        <label className="form-label required">Reason</label>
        <textarea className="form-textarea" value={reason} onChange={e => setReason(e.target.value)} placeholder={placeholder} rows={3} />
      </div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
        <button className="btn btn-ghost" onClick={onClose} disabled={loading}>Back</button>
        <button className="btn btn-primary" onClick={() => reason.trim() && onConfirm(reason.trim())} disabled={loading || !reason.trim()}>
          {loading ? <InlineSpinner /> : 'Confirm'}
        </button>
      </div>
    </Modal>
  );
}

// ─── MAIN PAGE ────────────────────────────────────────────────────────
export default function LeavePage() {
  const { user }  = useAuth();

  // Safe role check
  const roleStr = (user?.role || user?.Role || '').toLowerCase();
  const isManager = roleStr.includes('manager') || roleStr.includes('hr') || roleStr.includes('admin') || roleStr === 'supervisor';
  const isHR = roleStr.includes('hr') || roleStr.includes('admin');

  const [tab, setTab]             = useState('dashboard');
  const [balances, setBalances]   = useState([]);
  const [myRequests, setMyReqs]   = useState([]);
  const [allRequests, setAll]     = useState([]);
  const [leaveTypes, setTypes]    = useState([]);
  const [holidays, setHolidays]   = useState([]);

  const [loadBal, setLoadBal]     = useState(true);
  const [loadReq, setLoadReq]     = useState(true);
  const [loadAll, setLoadAll]     = useState(true);

  const [submitting, setSubmitting] = useState(false);
  const [historyFilter, setHistoryFilter] = useState('');
  const [allFilter, setAllFilter]       = useState('');
  const [reasonModal, setReasonModal] = useState(null); 
  const [actingReason, setActingReason] = useState(false);
  const [editingRequest, setEditingRequest] = useState(null);
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);

  const loadData = useCallback(() => {
    setLoadBal(true); setLoadReq(true);

    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).catch(console.warn).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests({ limit: 100 }).then(r => setMyReqs(toArr(r))).catch(console.warn).finally(() => setLoadReq(false));

    if (leaveAPI.getTypes) leaveAPI.getTypes().then(r => setTypes(toArr(r))).catch(() => {});
    if (leaveAPI.getHolidays) leaveAPI.getHolidays().then(r => setHolidays(toArr(r))).catch(() => {});

    if (isManager) {
      setLoadAll(true);
      leaveAPI.listAll({ limit: 100 }).then(r => setAll(toArr(r))).catch(console.warn).finally(() => setLoadAll(false));
    } else { setLoadAll(false); }
  }, [isManager]);

  useEffect(() => { loadData(); }, [loadData]);

  /* ── API Actions ── */
  const handleSubmit = async (form) => {
    setSubmitting(true);
    try {
      await leaveAPI.submit(form);
      toast.success('Leave request submitted!');
      setIsSubmitModalOpen(false);
      setTab('history');
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || err.message || 'Submit Failed'); } 
    finally { setSubmitting(false); }
  };

  const handleUpdate = async (formData) => {
    setSubmitting(true);
    try {
      const id = editingRequest.LeaveRequestID || editingRequest.id;
      await leaveAPI.updateRequest(id, formData);
      toast.success('Request updated!');
      setEditingRequest(null);
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Update Failed'); } 
    finally { setSubmitting(false); }
  };

  // Fixed Issue #2 (APPROVED / REJECTED strictly matches Joi requirements)
  const handleAction = async (id, action, reason) => {
    try {
      if (action === 'cancel') {
        if (!reason) { setReasonModal({ id, action: 'cancel' }); return; }
        await leaveAPI.cancel(id, { CancelReason: reason });
        toast.success('Request cancelled');
      } else if (action === 'approve') {
        await leaveAPI.approveReject(id, { decision: 'APPROVED', comments: '' });
        toast.success('Request approved');
      } else if (action === 'reject') {
        if (!reason) { setReasonModal({ id, action: 'reject' }); return; }
        await leaveAPI.approveReject(id, { decision: 'REJECTED', comments: reason });
        toast.success('Request rejected');
      }
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Action failed'); }
  };

  const handleReasonConfirm = async (reason) => {
    if (!reasonModal) return;
    setActingReason(true);
    try {
      await handleAction(reasonModal.id, reasonModal.action, reason);
      setReasonModal(null);
    } finally { setActingReason(false); }
  };

  // Fixed Issue #1: Override action mapped explicitly
  const handleOverride = async (requestId, newStatus, reason) => {
    try {
      await leaveAPI.approveReject(requestId, { decision: newStatus, comments: reason });
      toast.success(`Request overridden to ${newStatus}`);
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Override failed'); }
  };

  // Fixed Issue #3: Sync Payload matched to Router expectations
  const handlePayrollSync = async () => {
    try {
      const period = { periodYear: new Date().getFullYear(), periodMonth: new Date().getMonth() + 1 };
      const res = await leaveAPI.syncPayroll(period);
      toast.success(`Synced ${res.data?.data?.syncedCount || 'records'} to payroll`);
    } catch (err) { toast.error(err.response?.data?.message || "Payroll sync failed"); }
  };

  // Fixed Issue #4: Delegation logic triggers backend
  const handleDelegate = async (id, payload) => {
    try {
      await leaveAPI.delegate(id, payload);
      toast.success("Delegation successfully applied.");
    } catch(err) { toast.error(err.response?.data?.message || "Failed to set delegation"); }
  }

  const TABS = [
    { id: 'dashboard', label: 'Dashboard',    icon: BarChart2 },
    { id: 'history',   label: 'My History',   icon: Clock },
    ...(isManager ? [ { id: 'all', label: 'All Requests', icon: Calendar } ] : []),
    ...(isHR ? [ { id: 'settings', label: 'Settings', icon: Settings } ] : []),
  ];

  const filteredMyReqs  = myRequests.filter(r => statusMatches(r.Status || r.status, historyFilter));
  const filteredAllReqs = allRequests.filter(r => statusMatches(r.Status || r.status, allFilter));

  return (
    <>
      {reasonModal && <ReasonModal title={reasonModal.action === 'cancel' ? 'Cancel Leave Request' : 'Reject Leave Request'} placeholder={reasonModal.action === 'cancel' ? 'Reason for cancellation...' : 'Reason for rejection...'} onConfirm={handleReasonConfirm} onClose={() => setReasonModal(null)} loading={actingReason} />}
      {editingRequest && <EditRequestModal req={editingRequest} onSave={handleUpdate} onClose={() => setEditingRequest(null)} loading={submitting} />}
      {isSubmitModalOpen && (
        <div style={{ position: 'fixed', top:0, left:0, right:0, bottom:0, background:'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
          <div className="card" style={{ width: '100%', maxWidth: 600, maxHeight: '90vh', overflowY: 'auto' }}>
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
               <div className="card-title">Submit Leave Request</div>
               <button className="btn btn-ghost" onClick={() => setIsSubmitModalOpen(false)}><X size={18}/></button>
            </div>
            <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmit} loading={submitting} />
          </div>
        </div>
      )}

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
        <div>
          <h1>Leave Management</h1>
          <p>Manage leave requests, balances, and approvals</p>
        </div>
        <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}>
          <Plus size={18} style={{ marginRight: 8, verticalAlign: 'middle' }} /> New Request
        </button>
      </div>

      <div className="tabs">
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}>
            <Icon size={14} style={{ marginRight: 6, verticalAlign: 'middle' }} />{label}
          </button>
        ))}
      </div>

      {tab === 'dashboard' && (
        <>
          <div className="grid-4" style={{ marginBottom: 28 }}>
            {loadBal ? [1,2,3,4].map(i => <SkeletonCard key={i} />) : balances.length > 0
              ? balances.map((b, i) => <BalanceCard key={i} balance={b} loading={false} />)
              : <div style={{ gridColumn: '1 / -1', textAlign: 'center', padding: '32px 20px', color: 'var(--text-muted)', background: 'var(--surface)', borderRadius: 'var(--radius-lg)' }}><div style={{ fontWeight: 500 }}>No leave balances found</div></div>
            }
          </div>
          <div className="grid-2">
            <div className="card">
              <div className="card-header"><div className="card-title">Pending Requests</div></div>
              {myRequests.filter(r => !isFinalStatus(r.Status || r.status)).length === 0 ? (
                <div style={{ textAlign: 'center', padding: 30, color: 'var(--text-muted)', fontSize: '0.85rem' }}>No pending requests</div>
              ) : (
                myRequests.filter(r => !isFinalStatus(r.Status || r.status)).map((req, i) => {
                  const name = req.leaveTypeName || req.LeaveTypeName || req.leaveType?.LeaveTypeName || '—';
                  const days = req.numberOfDays ?? req.TotalDays ?? req.totalDays ?? req.days ?? '—';
                  return (
                    <div key={i} style={{ padding: '12px 0', borderBottom: '1px solid var(--border-light)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div style={{ fontWeight: 500, fontSize: '0.9rem' }}>{name}</div>
                      <div style={{ textAlign: 'right' }}><div style={{ fontWeight: 600 }}>{days !== '—' ? `${days} days` : '—'}</div><Badge status="Pending">Pending</Badge></div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </>
      )}

      {tab === 'history' && (
        <>
          <div className="filter-bar">
            {STATUS_HISTORY.map(({ value, label }) => <button key={value} className={`filter-chip ${historyFilter === value ? 'active' : ''}`} onClick={() => setHistoryFilter(value)}>{label}</button>)}
          </div>
          {loadReq ? <SkeletonCard /> : filteredMyReqs.length === 0 ? <div className="card"><div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-muted)' }}>No leave requests found</div></div> : (
            <div className="table-wrap">
              <table>
                <thead><tr><th>Leave Type</th><th>Period</th><th>Days</th><th>Status</th><th>Actions</th></tr></thead>
                <tbody>{filteredMyReqs.map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} onEdit={setEditingRequest} isManager={false} />)}</tbody>
              </table>
            </div>
          )}
        </>
      )}

      {tab === 'all' && isManager && (
        <>
          <div className="filter-bar">
            {STATUS_OPTIONS.map(({ value, label }) => <button key={value} className={`filter-chip ${allFilter === value ? 'active' : ''}`} onClick={() => setAllFilter(value)}>{label}</button>)}
          </div>
          {loadAll ? <SkeletonCard /> : filteredAllReqs.length === 0 ? <div className="card"><div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-muted)' }}>No leave requests found</div></div> : (
            <div className="table-wrap">
              <table>
                <thead><tr><th>Leave Type</th><th>Employee</th><th>Period</th><th>Days</th><th>Status</th><th>Reason</th><th>Actions</th></tr></thead>
                <tbody>{filteredAllReqs.map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} isManager={true} isHR={isHR} />)}</tbody>
              </table>
            </div>
          )}
        </>
      )}

      {tab === 'settings' && isHR && (
        <div className="grid-2">
           <PayrollSyncPanel onSync={handlePayrollSync} />
           <OverridePanel requests={allRequests} onOverride={handleOverride} />
           <DelegationPanel onDelegate={handleDelegate} />
        </div>
      )}
    </>
  );
}
